SELECT admin_id AS adminId, name, phone, role_id AS roleId, status, is_locked AS isLocked, fail_count AS failCount, created_at AS createdAt, updated_at AS UpdatedAt FROM admin_user WHERE status != 'DELETED'
AND (admin_id LIKE CONCAT('%', #{search}, '%') OR name LIKE CONCAT('%', #{search}, '%'))
AND role_id = #{role}
AND status = #{status}
ORDER BY CASE status WHEN 'INACTIVE' THEN 9 WHEN 'ACTIVE' THEN 1 ELSE 5 END ASC, CASE role_id WHEN 'SUPER' THEN 1 WHEN 'PROD' THEN 2 WHEN 'SALES' THEN 3 WHEN 'MATERIAL' THEN 4 ELSE 5 END ASC, admin_id ASC

